108→   * if the process is interrupted during write.
109→   */
110→  async saveState(state: WorkflowState): Promise<void> {
111→    // Validate before writing
112→    WorkflowStateSchema.parse(state);
113→
114→    // Update lastUpdated timestamp
115→    state.lastUpdated = new Date().toISOString();
116→
