439→  /**
440→   * Update the status of a specific acceptance criterion
441→   *
442→   * Used by /qa to mark individual ACs as met/not_met/blocked.
443→   * Automatically recalculates the summary counts.
444→   */
445→  async updateACStatus(
446→    issueNumber: number,
447→    acId: string,
448→    status: ACStatus,
449→    notes?: string,
450→  ): Promise<void> {
451→    const state = await this.getState();
452→    const issueState = state.issues[String(issueNumber)];
453→
454→    if (!issueState) {
455→      throw new Error(`Issue #${issueNumber} not found in state`);
456→    }
457→
458→    if (!issueState.acceptanceCriteria) {
459→      throw new Error(`Issue #${issueNumber} has no acceptance criteria`);
460→    }
461→
462→    // Find and update the AC item
463→    const acItem = issueState.acceptanceCriteria.items.find(
464→      (item) => item.id === acId,
465→    );
466→
467→    if (!acItem) {
468→      throw new Error(
469→        `AC "${acId}" not found in issue #${issueNumber}. ` +
470→          `Available IDs: ${issueState.acceptanceCriteria.items.map((i) => i.id).join(", ")}`,
471→      );
472→    }
473→
474→    acItem.status = status;
475→    acItem.verifiedAt = new Date().toISOString();
476→    if (notes !== undefined) {
477→      acItem.notes = notes;
478→    }
479→
480→    // Recalculate summary counts
481→    issueState.acceptanceCriteria = updateAcceptanceCriteriaSummary(
482→      issueState.acceptanceCriteria,
483→    );
484→    issueState.lastActivity = new Date().toISOString();
485→
486→    await this.saveState(state);
487→
488→    if (this.verbose) {
489→      console.log(`📊 AC ${acId} → ${status} for issue #${issueNumber}`);
490→    }
491→  }
492→
493→  // === Scope Assessment Operations ===
494→
495→  /**
496→   * Update scope assessment for an issue
497→   *
498→   * Used by /spec to store the scope assessment result.
499→   */
500→  async updateScopeAssessment(
501→    issueNumber: number,
502→    scopeAssessment: ScopeAssessment,
503→  ): Promise<void> {
504→    const state = await this.getState();
505→    const issueState = state.issues[String(issueNumber)];
506→
507→    if (!issueState) {
508→      throw new Error(`Issue #${issueNumber} not found in state`);
509→    }
510→
511→    issueState.scopeAssessment = scopeAssessment;
512→    issueState.lastActivity = new Date().toISOString();
513→
514→    await this.saveState(state);
515→
516→    if (this.verbose) {
517→      console.log(
518→        `📊 Scope assessment updated for issue #${issueNumber}: ${scopeAssessment.verdict}`,
519→      );
520→    }
521→  }
522→
523→  /**
524→   * Get scope assessment for an issue
525→   */
526→  async getScopeAssessment(
527→    issueNumber: number,
528→  ): Promise<ScopeAssessment | null> {
529→    const issueState = await this.getIssueState(issueNumber);
530→    return issueState?.scopeAssessment ?? null;
531→  }
532→
533→  // === Utility Operations ===
534→
535→  /**
536→   * Check if state file exists
537→   */
538→  stateExists(): boolean {
539→    return fs.existsSync(this.statePath);
540→  }
541→
542→  /**
543→   * Get issues in a specific status
544→   */
545→  async getIssuesByStatus(status: IssueStatus): Promise<IssueState[]> {
546→    const allStates = await this.getAllIssueStates();
547→    return Object.values(allStates).filter((s) => s.status === status);
548→  }
549→
550→  /**
551→   * Get issues currently in progress
552→   */
553→  async getInProgressIssues(): Promise<IssueState[]> {
554→    return this.getIssuesByStatus("in_progress");
555→  }
556→
557→  /**
558→   * Get issues ready for merge
559→   */
560→  async getReadyForMergeIssues(): Promise<IssueState[]> {
561→    return this.getIssuesByStatus("ready_for_merge");
562→  }
563→}
564→
565→// Export a default instance for convenience
566→let defaultManager: StateManager | null = null;
567→
568→/**
569→ * Get the default state manager instance
570→ */
571→export function getStateManager(options?: StateManagerOptions): StateManager {
572→  if (!defaultManager || options) {
573→    defaultManager = new StateManager(options);
